module NPU_SOC #(
    parameter CORES = 4
)(
    input wire clk,
    input wire rst_n,
    // 外部接口
    input wire [127:0] pcie_data,
    output reg [127:0] ddr_data,
    // 控制信号
    input wire interrupt,
    output reg [31:0] status
);

// 多核互连网络
wire [127:0] noc_data [0:CORES-1];
wire [31:0] noc_ctrl [0:CORES-1];

// 主控制器
npu_controller u_controller(
    .clk(clk),
    .rst_n(rst_n),
    .cores_status(noc_ctrl),
    .global_config(pcie_data[95:0]),
    .interrupt(interrupt)
);

// 计算核心阵列
generate
for (genvar i = 0; i < CORES; i = i + 1) begin
    npu_core #(
        .CORE_ID(i)
    ) u_core (
        .clk(clk),
        .rst_n(rst_n),
        .noc_in(noc_data[i]),
        .noc_out(noc_data[(i+1)%CORES]),
        .ctrl_in(noc_ctrl[i]),
        .ddr_interface(ddr_data)
    );
end
endgenerate

// 性能监控
performance_monitor u_monitor(
    .clk(clk),
    .cores_active(noc_ctrl),
    .ddr_usage(ddr_data[127:96]),
    .power_status(status[31:16])
);

endmodule

module PE_Array #(
    parameter DATA_WIDTH = 16,
    parameter ARRAY_SIZE = 8
)(
    input wire clk,
    input wire rst_n,
    input wire [DATA_WIDTH-1:0]  north_in [ARRAY_SIZE-1:0],
    input wire [DATA_WIDTH-1:0]  west_in  [ARRAY_SIZE-1:0],
    output wire [DATA_WIDTH-1:0] south_out[ARRAY_SIZE-1:0],
    output wire [DATA_WIDTH-1:0] east_out [ARRAY_SIZE-1:0],
    input wire [3:0]             opcode,
    input wire                   start,
    output wire                  done
);

wire [DATA_WIDTH-1:0] pe_data_h [ARRAY_SIZE][ARRAY_SIZE];
wire [DATA_WIDTH-1:0] pe_data_v [ARRAY_SIZE][ARRAY_SIZE];

generate
for (genvar i = 0; i < ARRAY_SIZE; i = i + 1) begin : row_gen
    for (genvar j = 0; j < ARRAY_SIZE; j = j + 1) begin : col_gen
        Processing_Element #(
            .DATA_WIDTH(DATA_WIDTH)
        ) u_pe (
            .clk(clk),
            .rst_n(rst_n),
            .north_in(i == 0 ? north_in[j] : pe_data_v[i-1][j]),
            .west_in(j == 0 ? west_in[i] : pe_data_h[i][j-1]),
            .south_out(pe_data_v[i][j]),
            .east_out(pe_data_h[i][j]),
            .opcode(opcode),
            .start(start),
            .done(done)
        );
    end
end
endgenerate

assign south_out = pe_data_v[ARRAY_SIZE-1];
assign east_out = pe_data_h[ARRAY_SIZE][ARRAY_SIZE-1];

endmodule

module Processing_Element #(
    parameter DATA_WIDTH = 16
)(
    input wire clk,
    input wire rst_n,
    input wire [DATA_WIDTH-1:0] north_in,
    input wire [DATA_WIDTH-1:0] west_in,
    output reg [DATA_WIDTH-1:0] south_out,
    output reg [DATA_WIDTH-1:0] east_out,
    input wire [3:0] opcode,
    input wire start,
    output reg done
);

reg [DATA_WIDTH-1:0] accumulator;
reg [DATA_WIDTH-1:0] weight_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        accumulator <= 0;
        weight_reg <= 0;
        done <= 0;
    end else begin
        case(opcode)
            4'h1: begin
                weight_reg <= west_in;
                done <= 1;
            end
            4'h2: begin
                accumulator <= accumulator + (north_in * weight_reg);
                done <= 1;
            end
            4'h3: begin
                south_out <= north_in;
                east_out <= west_in;
                done <= 1;
            end
            default: done <= 0;
        endcase
    end
end

endmodule

module Conv_Engine #(
    parameter KERNEL_SIZE = 3,
    parameter STRIDE = 1,
    parameter PAD = 1
)(
    input wire clk,
    input wire rst_n,
    input wire [7:0] feature_map [0:31][0:31],  // 32x32输入
    input wire [7:0] weight [0:2][0:2],         // 3x3卷积核
    output reg [15:0] conv_result [0:30][0:30]  // 输出特征图
);

// 滑动窗口生成器
reg [7:0] window_buffer [0:2][0:2];
always @(posedge clk) begin
    for (int i = 0; i <= 30; i++) begin
        for (int j = 0; j <= 30; j++) begin
            // 窗口滑动控制
            if (j == 0) begin
                window_buffer[0][0] <= (i > 0) ? feature_map[i-1][j+0] : 0;
                window_buffer[1][0] <= feature_map[i][j+0];
                window_buffer[2][0] <= (i < 31) ? feature_map[i+1][j+0] : 0;
            end else begin
                window_buffer[0][j%3] <= window_buffer[0][(j-1)%3];
                window_buffer[1][j%3] <= window_buffer[1][(j-1)%3];
                window_buffer[2][j%3] <= window_buffer[2][(j-1)%3];
            end

            // 卷积计算
            if (j >= 2) begin
                conv_result[i][j-2] <= 
                    (window_buffer[0][0] * weight[0][0]) +
                    (window_buffer[0][1] * weight[0][1]) +
                    (window_buffer[0][2] * weight[0][2]) +
                    (window_buffer[1][0] * weight[1][0]) +
                    (window_buffer[1][1] * weight[1][1]) +
                    (window_buffer[1][2] * weight[1][2]) +
                    (window_buffer[2][0] * weight[2][0]) +
                    (window_buffer[2][1] * weight[2][1]) +
                    (window_buffer[2][2] * weight[2][2]);
            end
        end
    end
end

endmodule

module Adaptive_PE #(
    parameter INT8_MODE = 1,
    parameter FP16_MODE = 0
)(
    input wire clk,
    input wire rst_n,
    input wire [3:0] precision_mode,
    input wire [31:0] din_a,
    input wire [31:0] din_b,
    output reg [31:0] dout
);

// 多精度计算单元
always @(posedge clk) begin
    if (!rst_n) dout <= 0;
    else begin
        case(precision_mode)
            4'b0001: // INT8模式
                dout <= $signed(din_a[7:0]) * $signed(din_b[7:0]);
            4'b0010: // FP16模式
                dout <= fp16_mult(din_a[15:0], din_b[15:0]);
            4'b0100: // BFLOAT16
                dout <= {din_a[31:16], 16'b0} * {din_b[31:16], 16'b0};
            default: // INT16
                dout <= $signed(din_a) * $signed(din_b);
        endcase
    end
end

// IEEE 754半精度浮点乘法实现
function [15:0] fp16_mult;
    input [15:0] a, b;
    begin
        fp16_mult[15] = a[15] ^ b[15];
        // 指数处理
        if (a[14:10] == 0 || b[14:10] == 0) 
            fp16_mult[14:10] = 0;
        else 
            fp16_mult[14:10] = a[14:10] + b[14:10] - 15;
        // 尾数处理
        fp16_mult[9:0] = (a[9:0] * b[9:0]) >> 10;
    end
endfunction

endmodule

module Memory_Controller #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 256,
    parameter BANK_NUM = 8
)(
    input wire clk,
    input wire rst_n,
    // 主机接口
    input wire [ADDR_WIDTH-1:0] host_addr,
    input wire                  host_wr_en,
    input wire [DATA_WIDTH-1:0] host_wr_data,
    output reg [DATA_WIDTH-1:0] host_rd_data,
    // NPU接口
    input wire [ADDR_WIDTH-1:0] npu_addr,
    input wire                  npu_rd_en,
    output reg [DATA_WIDTH-1:0] npu_rd_data
);

reg [DATA_WIDTH-1:0] memory_bank [0:BANK_NUM-1][0:(1<<(ADDR_WIDTH-3))-1];

always @(posedge clk) begin
    if (host_wr_en) begin
        memory_bank[host_addr[2:0]][host_addr[ADDR_WIDTH-1:3]] <= host_wr_data;
    end
    host_rd_data <= memory_bank[host_addr[2:0]][host_addr[ADDR_WIDTH-1:3]];

    if (npu_rd_en) begin
        npu_rd_data <= memory_bank[npu_addr[2:0]][npu_addr[ADDR_WIDTH-1:3]];
    end
end

// ECC校验
ecc_checker #(
    .DATA_WIDTH(DATA_WIDTH)
) u_ecc (
    .data_in(host_wr_data),
    .data_out(host_rd_data),
    .syndrome()
);

endmodule

module DVFS_Controller #(
    parameter VOLTAGE_LEVELS = 4,
    parameter FREQ_LEVELS = 4
)(
    input wire clk,
    input wire rst_n,
    input wire [7:0] workload,      // 0-255工作量指示
    output reg [1:0] voltage_level, // 00:0.8V ... 11:1.2V
    output reg [1:0] freq_level     // 00:500MHz ... 11:1.2GHz
);

reg [15:0] history_buffer [0:7];
always @(posedge clk) begin
    history_buffer <= {history_buffer[6:0], workload};
end

// 移动平均计算
wire [10:0] moving_avg;
assign moving_avg = (history_buffer[0] + history_buffer[1] + history_buffer[2] + 
                    history_buffer[3] + history_buffer[4] + history_buffer[5] +
                    history_buffer[6] + history_buffer[7]) >> 3;

// 调节策略
always @(*) begin
    case(moving_avg)
        0-50:   {voltage_level, freq_level} = 4'b00_00;
        51-100: {voltage_level, freq_level} = 4'b01_01;
        101-150:{voltage_level, freq_level} = 4'b10_10;
        default:{voltage_level, freq_level} = 4'b11_11;
    endcase
end

endmodule

module Sparse_Engine #(
    parameter SPARSE_THRESH = 0.3
)(
    input wire clk,
    input wire rst_n,
    input wire [7:0] activation [0:31][0:31],
    input wire [7:0] weight [0:31][0:31],
    output reg [15:0] sparse_result,
    output reg sparse_valid
);

// 零值检测逻辑
reg [31:0] zero_count;
always @(posedge clk) begin
    zero_count = 0;
    for (int i = 0; i < 32; i++) begin
        for (int j = 0; j < 32; j++) begin
            if (activation[i][j] == 0 || weight[i][j] == 0) begin
                zero_count <= zero_count + 1;
            end
        end
    end

    // 稀疏度判断
    if (zero_count > (32*32*SPARSE_THRESH)) begin
        sparse_valid <= 1'b1;
        // 触发稀疏计算模式
        sparse_result <= activation * weight; // 使用专用稀疏乘法器
    end else begin
        sparse_valid <= 1'b0;
    end
end

// 稀疏矩阵压缩格式处理
wire [7:0] compressed_act;
wire [4:0] act_idx;
sparse_encoder encoder(
    .in_data(activation),
    .compressed(compressed_act),
    .index(act_idx)
);

wire [7:0] compressed_weight;
wire [4:0] weight_idx;
sparse_encoder encoder_w(
    .in_data(weight),
    .compressed(compressed_weight),
    .index(weight_idx)
);

// 稀疏矩阵乘法核心
always @(posedge clk) begin
    if (act_idx == weight_idx) begin
        sparse_result <= compressed_act * compressed_weight;
    end
end

endmodule

module Shape_Adaptor #(
    parameter MAX_DIM = 4096
)(
    input wire clk,
    input wire rst_n,
    input wire [15:0] in_height,
    input wire [15:0] in_width,
    input wire [15:0] kernel_h,
    input wire [15:0] kernel_w,
    output reg [15:0] out_height,
    output reg [15:0] out_width,
    output reg pad_enable
);

// 动态形状计算
always @(posedge clk) begin
    // 输出尺寸计算
    out_height <= (in_height + 2*PAD - kernel_h) / STRIDE + 1;
    out_width  <= (in_width + 2*PAD - kernel_w) / STRIDE + 1;

    // 自动填充检测
    pad_enable <= ((in_height % STRIDE != 0) || 
                  (in_width % STRIDE != 0)) ? 1'b1 : 1'b0;

    // 边界保护
    if (out_height > MAX_DIM || out_width > MAX_DIM) begin
        $display("Error: Output dimension exceeds maximum limit!");
        out_height <= MAX_DIM;
        out_width <= MAX_DIM;
    end
end

// 运行时配置接口
task configure(
    input [15:0] new_stride,
    input [15:0] new_pad
);
    STRIDE = new_stride;
    PAD = new_pad;
endtask

endmodule

