#pragma once

#include <ntddk.h>
#include <wdf.h>

#define NPU_DEVICE_ID 0xBEEF
#define NPU_VENDOR_ID 0x1ACE

// IOCTL接口定义
#define NPU_IOCTL_BASE 0x800
#define IOCTL_NPU_EXECUTE \
    CTL_CODE(FILE_DEVICE_UNKNOWN, NPU_IOCTL_BASE + 0x0, METHOD_BUFFERED, FILE_ANY_ACCESS)
#define IOCTL_NPU_LOAD_WEIGHTS \
    CTL_CODE(FILE_DEVICE_UNKNOWN, NPU_IOCTL_BASE + 0x1, METHOD_BUFFERED, FILE_ANY_ACCESS)
#define IOCTL_NPU_GET_STATUS \
    CTL_CODE(FILE_DEVICE_UNKNOWN, NPU_IOCTL_BASE + 0x2, METHOD_BUFFERED, FILE_ANY_ACCESS)

// 硬件寄存器定义
typedef struct _NPU_REGISTERS {
    ULONG ControlStatus;
    ULONG InterruptMask;
    ULONG64 DmaSource;
    ULONG64 DmaDest;
    ULONG DmaLength;
} NPU_REGISTERS, *PNPU_REGISTERS;

// 设备上下文结构
typedef struct _DEVICE_CONTEXT {
    WDFDEVICE Device;
    NPU_REGISTERS* Registers;
    WDFDMAENABLER DmaEnabler;
    WDFINTERRUPT Interrupt;
    WDFSPINLOCK DmaLock;
    WDFQUEUE IoQueue;
} DEVICE_CONTEXT, *PDEVICE_CONTEXT;

WDF_DECLARE_CONTEXT_TYPE_WITH_NAME(DEVICE_CONTEXT, GetDeviceContext)

