10	NTSTATUS DriverEntry(PDRIVER_OBJECT DriverObject, PUNICODE_STRING RegistryPath) {
11	    WDF_DRIVER_CONFIG config;
12	    NTSTATUS status;
13	
14	    WDF_DRIVER_CONFIG_INIT(&config, NpuEvtDeviceAdd);
15	    config.DriverPoolTag = 'UPN';
16	
17	    status = WdfDriverCreate(DriverObject, RegistryPath, WDF_NO_OBJECT_ATTRIBUTES, &config, WDF_NO_HANDLE);
18	    if (!NT_SUCCESS(status)) {
19	        KdPrint(("WdfDriverCreate failed: 0x%x\n", status));
20	    }
21	    return status;
22	}
