24	NTSTATUS NpuEvtDeviceAdd(WDFDRIVER Driver, PWDFDEVICE_INIT DeviceInit) {
25	    NTSTATUS status;
26	    WDFDEVICE device;
27	    PDEVICE_CONTEXT devContext;
28	    WDF_PNPPOWER_EVENT_CALLBACKS pnpCallbacks;
29	    WDF_OBJECT_ATTRIBUTES attributes;
30	    WDF_INTERRUPT_CONFIG interruptConfig;
31	    WDF_IO_QUEUE_CONFIG ioQueueConfig;
32	
33	    WDF_PNPPOWER_EVENT_CALLBACKS_INIT(&pnpCallbacks);
34	    pnpCallbacks.EvtDevicePrepareHardware = NpuEvtPrepareHardware;
35	    WdfDeviceInitSetPnpPowerEventCallbacks(DeviceInit, &pnpCallbacks);
36	
37	    WDF_OBJECT_ATTRIBUTES_INIT_CONTEXT_TYPE(&attributes, DEVICE_CONTEXT);
38	    status = WdfDeviceCreate(&DeviceInit, &attributes, &device);
39	    if (!NT_SUCCESS(status)) {
40	        return status;
41	    }
42	
43	    devContext = GetDeviceContext(device);
44	    devContext->Device = device;
45	
46	    // 创建中断对象
47	    WDF_INTERRUPT_CONFIG_INIT(&interruptConfig, NpuEvtInterruptIsr, NpuEvtInterruptDpc);
48	    interruptConfig.InterruptTranslated = WdfUseHardwareInterrupts;
49	    status = WdfInterruptCreate(device, &interruptConfig, WDF_NO_OBJECT_ATTRIBUTES, &devContext->Interrupt);
50	    if (!NT_SUCCESS(status)) {
51	        return status;
52	    }
53	
54	    // 初始化DMA
55	    WDF_DMA_ENABLER_CONFIG dmaConfig;
56	    WDF_DMA_ENABLER_CONFIG_INIT(&dmaConfig, WdfDmaProfileScatterGather64, 64);
57	    status = WdfDmaEnablerCreate(device, &dmaConfig, WDF_NO_OBJECT_ATTRIBUTES, &devContext->DmaEnabler);
58	    if (!NT_SUCCESS(status)) {
59	        return status;
60	    }
61	
62	    // 创建IO队列
63	    WDF_IO_QUEUE_CONFIG_INIT_DEFAULT_QUEUE(&ioQueueConfig, WdfIoQueueDispatchParallel);
64	    ioQueueConfig.EvtIoDeviceControl = NpuEvtIoDeviceControl;
65	    status = WdfIoQueueCreate(device, &ioQueueConfig, WDF_NO_OBJECT_ATTRIBUTES, &devContext->IoQueue);
66	    if (!NT_SUCCESS(status)) {
67	        return status;
68	    }
69	
70	    return status;
71	}
72	
73	NTSTATUS NpuEvtPrepareHardware(WDFDEVICE Device, WDFCMRESLIST ResourcesRaw, WDFCMRESLIST ResourcesTranslated) {
74	    PCM_PARTIAL_RESOURCE_DESCRIPTOR resource;
75	    ULONG resourceCount;
76	    PDEVICE_CONTEXT devContext = GetDeviceContext(Device);
77	    NTSTATUS status = STATUS_SUCCESS;
78	
79	    resourceCount = WdfCmResourceListGetCount(ResourcesTranslated);
80	    for (ULONG i = 0; i < resourceCount; i++) {
81	        resource = WdfCmResourceListGetDescriptor(ResourcesTranslated, i);
82	        
83	        if (resource->Type == CmResourceTypeMemory) {
84	            devContext->Registers = (NPU_REGISTERS*)MmMapIoSpaceEx(
85	                resource->u.Memory.Start,
86	                resource->u.Memory.Length,
87	                PAGE_READWRITE | PAGE_NOCACHE);
88	            
89	            if (!devContext->Registers) {
90	                return STATUS_INSUFFICIENT_RESOURCES;
91	            }
92	        }
93	    }
94	
95	    // 初始化硬件
96	    WRITE_REGISTER_ULONG(&devContext->Registers->ControlStatus, 0x1); // 复位NPU
97	    KeStallExecutionProcessor(100);
98	    WRITE_REGISTER_ULONG(&devContext->Registers->ControlStatus, 0x0); // 解除复位
99	
100	    return status;
101	}
102	
103	VOID NpuEvtIoDeviceControl(WDFQUEUE Queue, WDFREQUEST Request, size_t OutputBufferLength,
104	                           size_t InputBufferLength, ULONG IoControlCode) {
105	    WDFDEVICE device = WdfIoQueueGetDevice(Queue);
106	    PDEVICE_CONTEXT devContext = GetDeviceContext(device);
107	    NTSTATUS status = STATUS_SUCCESS;
108	    size_t length = 0;
109	
110	    switch (IoControlCode) {
111	        case IOCTL_NPU_EXECUTE: {
112	            // 启动NPU运算
113	            WdfSpinLockAcquire(devContext->DmaLock);
114	            WRITE_REGISTER_ULONG(&devContext->Registers->ControlStatus, 0x2); // 启动计算
115	            WdfSpinLockRelease(devContext->DmaLock);
116	            length = 0;
117	            break;
118	        }
119	
120	        case IOCTL_NPU_LOAD_WEIGHTS: {
121	            PVOID inputBuffer;
122	            size_t bufferSize;
123	            WDFMEMORY dmaMemory;
124	            PVOID dmaBuffer;
125	            WDFDMATRANSACTION dmaTransaction;
126	
127	            status = WdfRequestRetrieveInputBuffer(Request, 0, &inputBuffer, &bufferSize);
128	            if (!NT_SUCCESS(status)) {
129	                break;
130	            }
131	
132	            // 分配DMA内存
133	            status = WdfDmaTransactionCreate(devContext->DmaEnabler, 
134	                WDF_DMA_ENABLER_CONFIG_REQUIRE_SINGLE_TRANSFER,
135	                WDF_NO_OBJECT_ATTRIBUTES, &dmaTransaction);
136	            if (!NT_SUCCESS(status)) {
137	                break;
138	            }
139	
140	            status = WdfMemoryCreateFromBuffer(
141	                WDF_NO_OBJECT_ATTRIBUTES,
142	                inputBuffer,
143	                bufferSize,
144	                &dmaMemory);
145	            if (!NT_SUCCESS(status)) {
146	                break;
147	            }
148	
149	            // 配置DMA传输
150	            WdfDmaTransactionInitialize(
151	                dmaTransaction,
152	                WdfDmaDirectionWriteToDevice,
153	                WdfMemoryGetBuffer(dmaMemory, NULL),
154	                bufferSize,
155	                devContext->Registers->DmaDest,
156	                devContext->Registers->DmaSource);
157	
158	            WdfDmaTransactionExecute(dmaTransaction, WDF_NO_CONTEXT);
159	            WdfObjectDelete(dmaTransaction);
160	            length = bufferSize;
161	            break;
162	        }
163	
164	        case IOCTL_NPU_GET_STATUS: {
165	            ULONG statusReg = READ_REGISTER_ULONG(&devContext->Registers->ControlStatus);
166	            status = WdfRequestCopyBuffer(Request, &statusReg, sizeof(ULONG));
167	            length = sizeof(ULONG);
168	            break;
169	        }
170	
171	        default:
172	            status = STATUS_INVALID_DEVICE_REQUEST;
173	            break;
174	    }
175	
176	    WdfRequestCompleteWithInformation(Request, status, length);
177	}
178	
179	BOOLEAN NpuEvtInterruptIsr(WDFINTERRUPT Interrupt, ULONG MessageID) {
180	    PDEVICE_CONTEXT devContext = GetDeviceContext(WdfInterruptGetDevice(Interrupt));
181	    ULONG status = READ_REGISTER_ULONG(&devContext->Registers->ControlStatus);
182	
183	    if (status & 0x80000000) { // 检查中断标志
184	        // 确认中断
185	        WRITE_REGISTER_ULONG(&devContext->Registers->InterruptMask, 0x1);
